void needle_openmp_shared_1(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int bx = omp_get_thread_num();
    int tx = 0; // Simulating threadIdx.x = 0 for this sequential adaptation within the loop structure

    // We need to simulate the block execution for each 'bx' that was a blockIdx in CUDA
    // In OpenMP, we will parallelize the outer loop over blocks if possible, but the inner logic 
    // of the CUDA kernel relies on shared memory and synchronization which must be converted to sequential logic per block
    // or carefully managed. Given the dependency pattern, we'll iterate blocks sequentially or parallelize carefully.
    // However, the original CUDA code runs blocks in parallel. To maintain correctness with dependencies handled inside,
    // we must ensure the logic per block is preserved.

    // Since the original CUDA loop iterates i from 1 to block_width and launches kernels for each block index,
    // and inside the kernel blockIdx.x varies.
    // The translation strategy: The outer loop in runTest iterates 'i'. Inside, it launches a kernel with dimGrid.x = i.
    // This means for a given 'i', there are 'i' blocks running in parallel.
    // We will use OpenMP to parallelize the blocks for a given 'i'.

    int current_bx = omp_get_thread_num(); 
    if (current_bx >= i) return; // Only threads corresponding to valid blocks execute

    int b_index_x = current_bx;
    int b_index_y = i - 1 - current_bx;

    int index   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols + 1);
    int index_n   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + 1;
    int index_w   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols;
    int index_nw  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    // Local arrays instead of shared memory
    int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
    int ref[BLOCK_SIZE][BLOCK_SIZE];

    // Initialize temp[0][0] equivalent
    temp[0][0] = matrix_cuda[index_nw];

    // Load ref
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        ref[ty][0] = referrence[index + cols * ty]; // tx is 0 in this simplified single-thread-per-block view? 
        // Wait, the CUDA kernel uses tx to load ref[ty][tx]. 
        // If we map one thread to one block, we must loop over tx as well.
        // But the CUDA kernel has BLOCK_SIZE threads per block.
        // To translate accurately without losing parallelism within the block (which is complex due to syncthreads),
        // we can treat the entire block computation as a single thread task in OpenMP, 
        // effectively sequentializing the intra-block parallelism but keeping inter-block parallelism.
        // This is a common approach for translating tightly synchronized CUDA kernels to OpenMP.

        for (int tx_inner = 0; tx_inner < BLOCK_SIZE; tx_inner++) {
            ref[ty][tx_inner] = referrence[index + cols * ty + tx_inner];
        }
    }

    // Load boundary conditions
    // if (tx == 0) temp[tx][0] ... -> temp[0][0] already set

    // temp[tx+1][0] = matrix_cuda[index_w + cols*tx]
    for (int tx_inner = 0; tx_inner < BLOCK_SIZE; tx_inner++) {
        temp[tx_inner+1][0] = matrix_cuda[index_w + cols * tx_inner];
    }

    // temp[0][tx+1] = matrix_cuda[index_n]
    for (int tx_inner = 0; tx_inner < BLOCK_SIZE; tx_inner++) {
        temp[0][tx_inner+1] = matrix_cuda[index_n + tx_inner]; // index_n is base, +tx moves along row? 
        // CUDA: index_n = base + tx + 1. 
        // matrix_cuda[index_n] where index_n depends on tx.
        // In CUDA: index_n = ... + tx + 1. So for each tx, it reads a different element.
        // Here: index_n calculated with tx=0 base? No, index_n definition in CUDA uses tx.
        // Let's recompute index_n for each tx_inner.
        int idx_n = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx_inner + 1;
        temp[0][tx_inner+1] = matrix_cuda[idx_n];
    }

    // First diagonal sweep
    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int tx_inner = 0; tx_inner <= m; tx_inner++) {
            int t_index_x = tx_inner + 1;
            int t_index_y = m - tx_inner + 1;

            temp[t_index_y][t_index_x] = maximum(
                temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                temp[t_index_y][t_index_x-1] - penalty,
                temp[t_index_y-1][t_index_x] - penalty
            );
        }
    }

    // Second diagonal sweep
    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        for (int tx_inner = 0; tx_inner <= m; tx_inner++) {
            int t_index_x = tx_inner + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx_inner;

            temp[t_index_y][t_index_x] = maximum(
                temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                temp[t_index_y][t_index_x-1] - penalty,
                temp[t_index_y-1][t_index_x] - penalty
            );
        }
    }

    // Write back
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        int idx_write = index + ty * cols;
        // CUDA: matrix_cuda[index + ty * cols] = temp[ty+1][tx+1];
        // But tx varies in CUDA. In our sequential block simulation, we must write all tx.
        // The CUDA kernel writes BLOCK_SIZE elements per block (one per thread).
        // So we need a loop here.
        for (int tx_inner = 0; tx_inner < BLOCK_SIZE; tx_inner++) {
            int idx_w = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx_inner + (cols + 1) + ty * cols;
            matrix_cuda[idx_w] = temp[ty+1][tx_inner+1];
        }
    }
}

